import React from 'react';
import { Category } from '../types';
import ProductCard from './ProductCard';
import { getImagePath } from '../utils';

interface CategorySectionProps {
  category: Category;
  quantities: Record<string, string>;
  onQuantityChange?: (imagePath: string, value: string) => void;
  readOnly?: boolean;
}

const CategorySection: React.FC<CategorySectionProps> = ({
  category,
  quantities,
  onQuantityChange,
  readOnly = false
}) => {
  return (
    <section style={{ marginBottom: '2rem', background: 'var(--color-bg-alt)', borderRadius: 'var(--radius)', padding: 'var(--space-3)' }}>
      <h2 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-2)' }}>{category.name}</h2>
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--space-2)' }}>
        {category.images.map((img) => {
          const imagePath = getImagePath(category.path, img);
          const quantity = quantities[imagePath] || '';

          return (
            <ProductCard
              key={img}
              categoryPath={category.path}
              imageName={img}
              quantity={quantity}
              onQuantityChange={onQuantityChange}
              readOnly={readOnly}
            />
          );
        })}
      </div>
    </section>
  );
};

export default CategorySection;
